    99→/**
   100→ * Process report generation job
   101→ *
   102→ * Generates PDF or Excel reports based on the job configuration.
   103→ * Saves output to file storage and returns download URL.
   104→ */
   105→export async function processReportJob(
   106→  context: WorkerJobContext<ReportJobData>
   107→): Promise<ReportResult> {
   108→  return withSpan('worker.report.process', async (span) => {
   109→    const { id, data } = context;
   110→    const { type, format, filters, requestedBy } = data;
   111→
   112→    span.setAttribute('jobId', id);
   113→    span.setAttribute('reportType', type);
   114→    span.setAttribute('format', format);
   115→    span.setAttribute('requestedBy', requestedBy);
   116→
   117→    log.info(
   118→      {
   119→        jobId: id,
   120→        type,
   121→        format,
   122→        requestedBy,
   123→        filters: Object.keys(filters ?? {}),
   124→      },
   125→      'Processing report generation job'
   126→    );
   127→
   128→    // Update progress: initializing
   129→    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
   130→    await context.log(`Initializing ${type} report generation (${format})`);
   131→
   132→    // Ensure output directory exists
   133→    await ensureOutputDir();
   134→
   135→    // Update progress: fetching data
   136→    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 20 });
   137→    await context.log('Fetching report data');
   138→
   139→    // Fetch data based on report type
   140→    const reportData = await fetchReportData(type, filters);
   141→    span.setAttribute('report.dataRows', reportData.rowCount);
   142→
   143→    await context.log(`Loaded ${reportData.rowCount} records for report`);
   144→
   145→    // Update progress: generating report
   146→    await context.updateProgress({ stage: 'GENERATING', percent: 50 });
   147→    await context.log(`Generating ${format.toUpperCase()} report`);
   148→
   149→    // Generate report based on format
   150→    let result: ReportResult;
   151→
   152→    if (format === 'excel') {
   153→      result = await generateExcelReport(id, type, reportData);
   154→    } else {
   155→      result = await generatePdfReport(id, type, reportData);
   156→    }
   157→
   158→    // Update progress: finalizing
   159→    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });
   160→
   161→    log.info(
   162→      {
   163→        jobId: id,
   164→        filePath: result.filePath,
   165→        fileSizeBytes: result.fileSizeBytes,
   166→        downloadUrl: result.downloadUrl,
   167→        expiresAt: result.expiresAt,
   168→      },
   169→      'Report generation complete'
   170→    );
   171→
   172→    await context.log(
   173→      `Report generated: ${result.fileName} (${formatFileSize(result.fileSizeBytes)})`
   174→    );
   175→    await context.log(`Download URL: ${result.downloadUrl}`);
   176→    await context.log(`Expires: ${result.expiresAt.toISOString()}`);
   177→
   178→    // Record metrics
   179→    span.setAttribute('report.fileSizeBytes', result.fileSizeBytes);
   180→    span.setAttribute('report.fileName', result.fileName);
   181→
   182→    // Update progress: complete
   183→    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
   184→
   185→    return result;
   186→  });
   187→}
