   285→/**
   286→ * Fetch PM schedule data from database
   287→ */
   288→async function fetchPmScheduleData(filters?: Record<string, unknown>): Promise<ReportData> {
   289→  // Parse filters
   290→  const startDate = filters?.['startDate'] as string | undefined;
   291→  const endDate = filters?.['endDate'] as string | undefined;
   292→  const fleetId = filters?.['fleetId'] as string | undefined;
   293→  const depotId = filters?.['depotId'] as string | undefined;
   294→  const statusFilter = filters?.['status'] as string[] | undefined;
   295→
   296→  // Build query conditions
   297→  const conditions = [isNull(pmSchedule.scenarioId)];
   298→
   299→  if (startDate) {
   300→    conditions.push(gte(pmSchedule.targetDate, startDate));
   301→  }
   302→  if (endDate) {
   303→    conditions.push(lte(pmSchedule.targetDate, endDate));
   304→  }
   305→  if (statusFilter?.length) {
   306→    conditions.push(inArray(pmSchedule.status, statusFilter as ('SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'DEFERRED' | 'CANCELLED')[]));
   307→  }
   308→  if (fleetId) {
   309→    conditions.push(eq(fleets.id, fleetId));
   310→  }
   311→  if (depotId) {
   312→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
   313→  }
   314→
   315→  // Query with joins
   316→  const results = await db
   317→    .select({
   318→      trainNumber: trains.trainNumber,
   319→      fleetCode: fleets.code,
   320→      pmCode: pmTypes.pmCode,
   321→      targetDate: pmSchedule.targetDate,
   322→      status: pmSchedule.status,
   323→      constraintStart: pmSchedule.constraintStart,
   324→      constraintEnd: pmSchedule.constraintEnd,
   325→      assignedDepot: depots.name,
   326→      assignedTrack: tracks.trackNumber,
   327→      estimatedHours: pmTypes.estimatedHours,
   328→      maximoWoId: pmSchedule.maximoWoId,
   329→      isLocked: pmSchedule.isLocked,
   330→    })
   331→    .from(pmSchedule)
   332→    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   333→    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
   334→    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
   335→    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
   336→    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
   337→    .where(and(...conditions))
   338→    .orderBy(asc(pmSchedule.targetDate), asc(trains.trainNumber));
   339→
   340→  const rows: PmScheduleRow[] = results.map((r) => ({
   341→    trainNumber: r.trainNumber,
   342→    fleetCode: r.fleetCode,
   343→    pmCode: r.pmCode,
   344→    targetDate: r.targetDate,
   345→    status: r.status ?? 'SCHEDULED', // Default to SCHEDULED if null
   346→    constraintStart: r.constraintStart,
   347→    constraintEnd: r.constraintEnd,
   348→    assignedDepot: r.assignedDepot,
   349→    assignedTrack: r.assignedTrack,
   350→    estimatedHours: r.estimatedHours ? Number(r.estimatedHours) : null,
   351→    maximoWoId: r.maximoWoId,
   352→    isLocked: r.isLocked ?? false, // Default to false if null
   353→  }));
   354→
   355→  return {
   356→    rowCount: rows.length,
   357→    data: rows as unknown as Record<string, unknown>[],
   358→    metadata: {
   359→      reportType: 'pm_schedule',
   360→      columns: [
   361→        'trainNumber', 'fleetCode', 'pmCode', 'targetDate', 'status',
   362→        'constraintStart', 'constraintEnd', 'assignedDepot', 'assignedTrack',
   363→        'estimatedHours', 'maximoWoId', 'isLocked',
   364→      ],
   365→      generatedAt: new Date().toISOString(),
   366→      filters: { startDate, endDate, fleetId, depotId, status: statusFilter },
   367→    },
   368→  };
   369→}
