   374→async function fetchFleetStatusData(filters?: Record<string, unknown>): Promise<ReportData> {
   375→  const fleetService = getFleetService();
   376→
   377→  // Get all fleet statistics
   378→  const allStats = await fleetService.getAllFleetStatistics();
   379→
   380→  // Optionally filter by fleetId
   381→  const fleetId = filters?.['fleetId'] as string | undefined;
   382→  const filteredStats = fleetId
   383→    ? allStats.filter((s) => s.fleetId === fleetId || s.fleetCode === fleetId)
   384→    : allStats;
   385→
   386→  const rows: FleetStatusRow[] = filteredStats.map((s: FleetStatistics) => ({
   387→    fleetCode: s.fleetCode,
   388→    fleetName: s.fleetCode, // FleetStatistics has fleetCode but not fleetName
   389→    totalTrains: s.totalTrains,
   390→    fitTrains: s.fitTrains,
   391→    restrictedTrains: s.restrictedTrains,
   392→    groundedTrains: s.groundedTrains,
   393→    avgMileageKm: Math.round(s.averageMileageKm),
   394→    minMileageKm: s.minMileageKm,
   395→    maxMileageKm: s.maxMileageKm,
   396→    stdDevMileageKm: Math.round(s.mileageStdDevKm),
   397→  }));
   398→
   399→  return {
   400→    rowCount: rows.length,
   401→    data: rows as unknown as Record<string, unknown>[],
   402→    metadata: {
   403→      reportType: 'fleet_status',
   404→      columns: [
   405→        'fleetCode', 'fleetName', 'totalTrains', 'fitTrains', 'restrictedTrains',
   406→        'groundedTrains', 'avgMileageKm', 'minMileageKm', 'maxMileageKm', 'stdDevMileageKm',
