   414→/**
   415→ * Fetch drift report data using DriftMonitorService
   416→ */
   417→async function fetchDriftReportData(filters?: Record<string, unknown>): Promise<ReportData> {
   418→  const driftService = getDriftMonitorService();
   419→
   420→  // Run or get latest drift analysis
   421→  const analysisDate = filters?.['analysisDate'] as string | undefined;
   422→  const analysisDateObj = analysisDate ? new Date(analysisDate) : undefined;
   423→  const result: DriftAnalysisResult = await driftService.runDriftAnalysis(analysisDateObj);
   424→
   425→  // Check if analysis was skipped (discriminated union check)
   426→  if (result.skipped) {
   427→    return {
   428→      rowCount: 0,
   429→      data: [],
   430→      metadata: {
   431→        reportType: 'drift_report',
   432→        status: 'SKIPPED',
   433→        reason: result.reason,
   434→        generatedAt: new Date().toISOString(),
   435→        filters,
   436→      },
   437→    };
   438→  }
   439→
   440→  // Type narrowing - result is now DriftAnalysisSuccess
   441→  const successResult = result as DriftAnalysisSuccess;
   442→
   443→  // Extract train analyses
   444→  const trainAnalyses = successResult.trainAnalyses;
   445→
   446→  const rows: DriftReportRow[] = trainAnalyses.map((t: TrainDriftAnalysis) => ({
   447→    trainNumber: t.trainNumber,
   448→    fleetCode: '', // TrainDriftAnalysis doesn't have fleetCode; would need separate lookup
   449→    baselineProjectedKm: t.baselineProjectedKm,
   450→    actualKm: t.actualKm,
   451→    mileageDriftPct: t.mileageDriftPct,
   452→    avgPmDriftDays: t.avgPmDriftDays,
   453→    maxPmDriftDays: t.maxPmDriftDays,
   454→    requiresReplan: t.requiresReplan,
   455→    replanReason: t.replanReason ?? null,
   456→  }));
   457→
   458→  // Get summary and alerts
   459→  const summary = successResult.summary;
   460→  const alerts = successResult.alerts;
   461→
   462→  return {
   463→    rowCount: rows.length,
   464→    data: rows as unknown as Record<string, unknown>[],
   465→    metadata: {
   466→      reportType: 'drift_report',
   467→      baselineId: successResult.baselineId,
   468→      analysisDate: successResult.analysisDate,
   469→      summary: {
   470→        totalTrainsAnalyzed: summary.totalTrains,
   471→        trainsRequiringReplan: summary.trainsRequiringReplan,
   472→        avgMileageDriftPct: summary.avgFleetDriftPct,
   473→        maxPmDriftDays: 0, // Not directly available in summary, would need to calculate
   474→      },
   475→      alerts: alerts.map((a: DriftAlert) => ({
   476→        severity: a.severity,
   477→        type: a.type,
   478→        message: a.message,
   479→        trainNumber: a.trainNumber,
   480→      })),
   481→      columns: [
   482→        'trainNumber', 'fleetCode', 'baselineProjectedKm', 'actualKm', 'mileageDriftPct',
   483→        'avgPmDriftDays', 'maxPmDriftDays', 'requiresReplan', 'replanReason',
   484→      ],
   485→      generatedAt: new Date().toISOString(),
   486→      filters,
   487→    },
   488→  };
   489→}
