   491→/**
   492→ * Fetch TCO projection data using CostingService
   493→ */
   494→async function fetchTcoProjectionData(filters?: Record<string, unknown>): Promise<ReportData> {
   495→  const costingService = getCostingService();
   496→
   497→  // Parse filters - ProjectTCORequest only has horizonYears, scenarioId, depotId
   498→  const horizonYears = (filters?.['horizonYears'] as number) ?? 12;
   499→  const depotId = filters?.['depotId'] as string | undefined;
   500→  const scenarioId = filters?.['scenarioId'] as string | undefined;
   501→
   502→  // Project TCO
   503→  const projection: TCOProjection = await costingService.projectTCO({
   504→    horizonYears,
   505→    depotId,
   506→    scenarioId,
   507→  });
   508→
   509→  // Calculate overhead as 18% of (labor + material) for each year
   510→  const OVERHEAD_RATE = 0.18;
   511→  const rows: TcoProjectionRow[] = projection.projections.map((p: YearlyCost) => {
   512→    const overheadCost = (p.laborCost + p.materialCost) * OVERHEAD_RATE;
   513→    return {
   514→      fiscalYear: p.fiscalYear,
   515→      laborCost: p.laborCost,
   516→      materialCost: p.materialCost,
   517→      overheadCost: Math.round(overheadCost),
   518→      totalCost: p.totalCost,
   519→      pmCount: p.pmCount,
   520→      inflationFactor: p.inflationFactor,
   521→    };
   522→  });
   523→
   524→  // Calculate total overhead cost from the rows
   525→  const totalOverheadCost = rows.reduce((sum, r) => sum + r.overheadCost, 0);
   526→
   527→  return {
   528→    rowCount: rows.length,
   529→    data: rows as unknown as Record<string, unknown>[],
   530→    metadata: {
   531→      reportType: 'tco_projection',
   532→      horizonYears,
   533→      summary: {
   534→        totalLaborCost: projection.summary.totalLaborCost,
   535→        totalMaterialCost: projection.summary.totalMaterialCost,
   536→        totalOverheadCost: totalOverheadCost,
   537→        grandTotal: projection.summary.totalCost,
   538→        npv: projection.summary.npv,
   539→        avgAnnualCost: projection.summary.avgAnnualCost,
   540→      },
   541→      columns: [
   542→        'fiscalYear', 'laborCost', 'materialCost', 'overheadCost', 'totalCost',
   543→        'pmCount', 'inflationFactor',
   544→      ],
   545→      generatedAt: new Date().toISOString(),
   546→      filters: { horizonYears, depotId, scenarioId },
   547→    },
   548→  };
   549→}
