   555→/**
   556→ * Generate Excel report using ExcelJS
   557→ */
   558→async function generateExcelReport(
   559→  jobId: string,
   560→  type: string,
   561→  reportData: ReportData
   562→): Promise<ReportResult> {
   563→  return withSpan('report.generateExcel', async (span) => {
   564→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
   565→    const fileName = `${type}_${timestamp}.xlsx`;
   566→    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);
   567→
   568→    span.setAttribute('report.fileName', fileName);
   569→    span.setAttribute('report.filePath', filePath);
   570→
   571→    // Create workbook and worksheet
   572→    const workbook = new ExcelJS.Workbook();
   573→    workbook.creator = 'MMS Report Generator';
   574→    workbook.created = new Date();
   575→
   576→    const worksheet = workbook.addWorksheet(formatReportTitle(type));
   577→
   578→    // Get columns from metadata
   579→    const columns = (reportData.metadata['columns'] as string[]) ?? [];
   580→
   581→    // Configure columns with headers and widths
   582→    worksheet.columns = columns.map((col) => ({
   583→      header: formatColumnHeader(col),
   584→      key: col,
   585→      width: getColumnWidth(col),
   586→    }));
   587→
   588→    // Style header row
   589→    const headerRow = worksheet.getRow(1);
   590→    headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
   591→    headerRow.fill = {
   592→      type: 'pattern',
   593→      pattern: 'solid',
   594→      fgColor: { argb: 'FF2E5A88' }, // MMS blue
   595→    };
   596→    headerRow.alignment = { vertical: 'middle', horizontal: 'center' };
   597→
   598→    // Add data rows
   599→    reportData.data.forEach((row) => {
   600→      const rowData: Record<string, unknown> = {};
   601→      columns.forEach((col) => {
   602→        rowData[col] = formatCellValue(row[col], col);
   603→      });
   604→      worksheet.addRow(rowData);
   605→    });
   606→
   607→    // Apply alternating row colors
   608→    worksheet.eachRow((row, rowNumber) => {
   609→      if (rowNumber > 1 && rowNumber % 2 === 0) {
   610→        row.fill = {
   611→          type: 'pattern',
   612→          pattern: 'solid',
   613→          fgColor: { argb: 'FFF5F5F5' },
   614→        };
   615→      }
   616→    });
   617→
   618→    // Add filters to first row if supported
   619→    if (reportData.rowCount > 0) {
   620→      worksheet.autoFilter = {
   621→        from: { row: 1, column: 1 },
   622→        to: { row: 1, column: columns.length },
   623→      };
   624→    }
   625→
   626→    // Add metadata sheet
   627→    const metaSheet = workbook.addWorksheet('Report Info');
   628→    metaSheet.addRow(['Report Type', formatReportTitle(type)]);
   629→    metaSheet.addRow(['Generated At', reportData.metadata['generatedAt']]);
   630→    metaSheet.addRow(['Total Records', reportData.rowCount]);
   631→
   632→    // Add summary data for specific report types
