   725→/**
   726→ * Format column header from camelCase to Title Case
   727→ */
   728→function formatColumnHeader(col: string): string {
   729→  return col
   730→    .replace(/([A-Z])/g, ' $1')
   731→    .replace(/^./, (str) => str.toUpperCase())
   732→    .replace(/Km/g, '(km)')
   733→    .replace(/Pct/g, '(%)')
   734→    .trim();
   735→}
   736→
   737→/**
   738→ * Format cell value for display
   739→ */
   740→function formatCellValue(value: unknown, col: string): string | number | boolean | Date | null {
   741→  if (value === null || value === undefined) return '';
   742→
   743→  // Currency columns
   744→  if (['laborCost', 'materialCost', 'overheadCost', 'totalCost'].includes(col)) {
   745→    return typeof value === 'number' ? value : parseFloat(String(value)) || 0;
   746→  }
   747→
   748→  // Percentage columns
   749→  if (col.includes('Pct')) {
   750→    return typeof value === 'number' ? `${value.toFixed(2)}%` : String(value);
   751→  }
   752→
   753→  // Boolean columns
   754→  if (typeof value === 'boolean') {
   755→    return value ? 'Yes' : 'No';
   756→  }
   757→
   758→  // Date columns
   759→  if (col.includes('Date') && typeof value === 'string') {
   760→    return value;
   761→  }
   762→
   763→  return value as string | number | boolean | Date;
   764→}
   765→
   766→/**
   767→ * Format currency value
   768→ */
   769→function formatCurrency(value: number | undefined): string {
   770→  if (value === undefined) return 'N/A';
   771→  return new Intl.NumberFormat('en-SG', {
   772→    style: 'currency',
   773→    currency: 'SGD',
   774→    minimumFractionDigits: 0,
   775→    maximumFractionDigits: 0,
   776→  }).format(value);
   777→}
