   793→/**
   794→ * Generate PDF report using pdfmake
   795→ */
   796→async function generatePdfReport(
   797→  jobId: string,
   798→  type: string,
   799→  reportData: ReportData
   800→): Promise<ReportResult> {
   801→  return withSpan('report.generatePdf', async (span) => {
   802→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
   803→    const fileName = `${type}_${timestamp}.pdf`;
   804→    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);
   805→
   806→    span.setAttribute('report.fileName', fileName);
   807→    span.setAttribute('report.filePath', filePath);
   808→
   809→    // Create PDF document definition
   810→    const docDefinition = createPdfDocDefinition(type, reportData);
   811→
   812→    // Create PDF printer
   813→    const printer = new PdfPrinter(fonts);
   814→    const pdfDoc = printer.createPdfKitDocument(docDefinition);
   815→
   816→    // Write to file using synchronous fs createWriteStream
   817→    await new Promise<void>((resolve, reject) => {
   818→      const writeStream = fsSync.createWriteStream(filePath);
   819→      pdfDoc.pipe(writeStream);
   820→      pdfDoc.end();
   821→      writeStream.on('finish', resolve);
   822→      writeStream.on('error', reject);
   823→    });
   824→
   825→    const stats = await fs.stat(filePath);
   826→    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);
   827→
   828→    // Estimate page count (roughly 40 rows per page in landscape)
   829→    const estimatedPageCount = Math.max(1, Math.ceil(reportData.rowCount / 40));
   830→
   831→    return {
   832→      jobId,
   833→      type,
   834→      format: 'pdf',
   835→      filePath,
   836→      fileName,
   837→      fileSizeBytes: stats.size,
   838→      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
   839→      expiresAt,
   840→      generatedAt: new Date(),
   841→      rowCount: reportData.rowCount,
   842→      pageCount: estimatedPageCount,
   843→    };
   844→  });
   845→}
