   996→/**
   997→ * Create data table for PDF
   998→ */
   999→function createDataTable(columns: string[], data: Record<string, unknown>[]): Content {
  1000→  // Limit columns displayed based on page width
  1001→  const displayColumns = columns.slice(0, 10);
  1002→
  1003→  // Header row
  1004→  const headerRow: TableCell[] = displayColumns.map((col) => ({
  1005→    text: formatColumnHeader(col),
  1006→    style: 'tableHeader',
  1007→    alignment: 'center',
  1008→  }));
  1009→
  1010→  // Data rows
  1011→  const dataRows: TableCell[][] = data.map((row, index) =>
  1012→    displayColumns.map((col) => ({
  1013→      text: String(formatCellValue(row[col], col) ?? ''),
  1014→      style: index % 2 === 0 ? 'tableCell' : 'tableCellAlt',
  1015→      alignment: isNumericColumn(col) ? 'right' : 'left',
  1016→    }))
  1017→  );
  1018→
  1019→  // Calculate column widths (equal distribution)
  1020→  const colWidth = (842 - 80) / displayColumns.length; // A4 landscape width minus margins
  1021→  const widths = displayColumns.map(() => colWidth);
  1022→
  1023→  return {
  1024→    table: {
  1025→      headerRows: 1,
  1026→      widths,
  1027→      body: [headerRow, ...dataRows],
  1028→    },
  1029→    layout: {
  1030→      hLineWidth: () => 0.5,
  1031→      vLineWidth: () => 0.5,
  1032→      hLineColor: () => '#DDDDDD',
  1033→      vLineColor: () => '#DDDDDD',
  1034→      paddingLeft: () => 4,
  1035→      paddingRight: () => 4,
  1036→      paddingTop: () => 2,
  1037→      paddingBottom: () => 2,
  1038→    },
  1039→  };
  1040→}
