  1219→    await fs.access(REPORTS_OUTPUT_DIR);
  1220→  } catch {
  1221→    await fs.mkdir(REPORTS_OUTPUT_DIR, { recursive: true });
  1222→    log.info({ dir: REPORTS_OUTPUT_DIR }, 'Created reports output directory');
  1223→  }
  1224→}
