/**
 * MMS Report Worker Processor
 *
 * BullMQ job processor for PDF and Excel report generation.
 * Handles export of PM schedules, fleet status, and various analytical reports.
 *
 * Supported Report Types:
 * - pm_schedule: PM Schedule export (Excel/CSV)
 * - fleet_status: Fleet status overview (PDF)
 * - drift_report: Drift analysis report (PDF)
 * - tco_projection: Total Cost of Ownership projection (PDF)
 *
 * Report Generation:
 * - Excel: Uses ExcelJS for .xlsx generation with formatting
 * - PDF: Uses pdfmake for PDF generation with structured layouts
 *
 * Job Flow:
 * 1. Receive ReportJobData from queue
 * 2. Fetch data based on report type and filters
 * 3. Generate report in requested format
 * 4. Save to file storage
 * 5. Update job status with download URL
 *
 * @see specs/005-api.md Section 5.15
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type ReportJobData } from '../../lib/queue';
import { ValidationError } from '../../lib/errors';
import * as fs from 'fs/promises';
import * as fsSync from 'fs';
import * as path from 'path';
import ExcelJS from 'exceljs';
import PdfPrinter from 'pdfmake';
import type { TDocumentDefinitions, Content, TableCell } from 'pdfmake/interfaces';

// Domain services for data fetching
import { getFleetService, type FleetStatistics } from '../../services/fleet';
import {
  getDriftMonitorService,
  type TrainDriftAnalysis,
  type DriftAlert,
  type DriftAnalysisResult,
  type DriftAnalysisSuccess,
} from '../../services/drift-monitor';
import { getCostingService, type TCOProjection, type YearlyCost } from '../../services/costing';
import { db } from '../../lib/db/connection';
import {
  pmSchedule,
  trains,
  pmTypes,
  depots,
  tracks,
  fleets,
} from '../../lib/db/schema';
import { eq, and, gte, lte, isNull, inArray, asc } from 'drizzle-orm';
import { format } from 'date-fns';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'report' });

/** Output directory for generated reports */
const REPORTS_OUTPUT_DIR = process.env['REPORTS_OUTPUT_DIR'] ?? '/tmp/mms-reports';

/** Base URL for report downloads */
const REPORTS_BASE_URL = process.env['REPORTS_BASE_URL'] ?? 'http://localhost:3000/exports';

/** Report retention period in hours */
const REPORT_RETENTION_HOURS = parseInt(process.env['REPORT_RETENTION_HOURS'] ?? '24', 10);

// =============================================================================
// Types
// =============================================================================

/** Report generation result */
export interface ReportResult {
  jobId: string;
  type: string;
  format: 'pdf' | 'excel';
  filePath: string;
  fileName: string;
  fileSizeBytes: number;
  downloadUrl: string;
  expiresAt: Date;
  generatedAt: Date;
  rowCount?: number;
  pageCount?: number;
}

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process report generation job
 *
 * Generates PDF or Excel reports based on the job configuration.
 * Saves output to file storage and returns download URL.
 */
export async function processReportJob(
  context: WorkerJobContext<ReportJobData>
): Promise<ReportResult> {
  return withSpan('worker.report.process', async (span) => {
    const { id, data } = context;
    const { type, format, filters, requestedBy } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('reportType', type);
    span.setAttribute('format', format);
    span.setAttribute('requestedBy', requestedBy);

    log.info(
      {
        jobId: id,
        type,
        format,
        requestedBy,
        filters: Object.keys(filters ?? {}),
      },
      'Processing report generation job'
    );

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
    await context.log(`Initializing ${type} report generation (${format})`);

    // Ensure output directory exists
    await ensureOutputDir();

    // Update progress: fetching data
    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 20 });
    await context.log('Fetching report data');

    // Fetch data based on report type
    const reportData = await fetchReportData(type, filters);
    span.setAttribute('report.dataRows', reportData.rowCount);

    await context.log(`Loaded ${reportData.rowCount} records for report`);

    // Update progress: generating report
    await context.updateProgress({ stage: 'GENERATING', percent: 50 });
    await context.log(`Generating ${format.toUpperCase()} report`);

    // Generate report based on format
    let result: ReportResult;

    if (format === 'excel') {
      result = await generateExcelReport(id, type, reportData);
    } else {
      result = await generatePdfReport(id, type, reportData);
    }

    // Update progress: finalizing
    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

    log.info(
      {
        jobId: id,
        filePath: result.filePath,
        fileSizeBytes: result.fileSizeBytes,
        downloadUrl: result.downloadUrl,
        expiresAt: result.expiresAt,
      },
      'Report generation complete'
    );

    await context.log(
      `Report generated: ${result.fileName} (${formatFileSize(result.fileSizeBytes)})`
    );
    await context.log(`Download URL: ${result.downloadUrl}`);
    await context.log(`Expires: ${result.expiresAt.toISOString()}`);

    // Record metrics
    span.setAttribute('report.fileSizeBytes', result.fileSizeBytes);
    span.setAttribute('report.fileName', result.fileName);

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

// =============================================================================
// Data Fetching
// =============================================================================

interface ReportData {
  rowCount: number;
  data: Record<string, unknown>[];
  metadata: Record<string, unknown>;
}

/** PM Schedule row for report */
interface PmScheduleRow {
  trainNumber: string;
  fleetCode: string;
  pmCode: string;
  targetDate: string;
  status: string;
  constraintStart: string | null;
  constraintEnd: string | null;
  assignedDepot: string | null;
  assignedTrack: string | null;
  estimatedHours: number | null;
  maximoWoId: string | null;
  isLocked: boolean;
}

/** Fleet status row for report */
interface FleetStatusRow {
  fleetCode: string;
  fleetName: string;
  totalTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  avgMileageKm: number;
  minMileageKm: number;
  maxMileageKm: number;
  stdDevMileageKm: number;
}

/** Drift report row for report */
interface DriftReportRow {
  trainNumber: string;
  fleetCode: string;
  baselineProjectedKm: number;
  actualKm: number;
  mileageDriftPct: number;
  avgPmDriftDays: number;
  maxPmDriftDays: number;
  requiresReplan: boolean;
  replanReason: string | null;
}

/** TCO projection row for report */
interface TcoProjectionRow {
  fiscalYear: number;
  laborCost: number;
  materialCost: number;
  overheadCost: number;
  totalCost: number;
  pmCount: number;
  inflationFactor: number;
}

/**
 * Fetch data for report generation
 */
async function fetchReportData(
  type: string,
  filters?: Record<string, unknown>
): Promise<ReportData> {
  return withSpan('report.fetchData', async (span) => {
    span.setAttribute('reportType', type);

    switch (type) {
      case 'pm_schedule':
        return fetchPmScheduleData(filters);

      case 'fleet_status':
        return fetchFleetStatusData(filters);

      case 'drift_report':
        return fetchDriftReportData(filters);

      case 'tco_projection':
        return fetchTcoProjectionData(filters);

      default:
        throw new ValidationError(`Unsupported report type: ${type}`, {
          field: 'type',
          context: { supported: ['pm_schedule', 'fleet_status', 'drift_report', 'tco_projection'] },
        });
    }
  });
}

/**
 * Fetch PM schedule data from database
 */
async function fetchPmScheduleData(filters?: Record<string, unknown>): Promise<ReportData> {
  // Parse filters
  const startDate = filters?.['startDate'] as string | undefined;
  const endDate = filters?.['endDate'] as string | undefined;
  const fleetId = filters?.['fleetId'] as string | undefined;
  const depotId = filters?.['depotId'] as string | undefined;
  const statusFilter = filters?.['status'] as string[] | undefined;

  // Build query conditions
  const conditions = [isNull(pmSchedule.scenarioId)];

  if (startDate) {
    conditions.push(gte(pmSchedule.targetDate, startDate));
  }
  if (endDate) {
    conditions.push(lte(pmSchedule.targetDate, endDate));
  }
  if (statusFilter?.length) {
    conditions.push(inArray(pmSchedule.status, statusFilter as ('SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'DEFERRED' | 'CANCELLED')[]));
  }
  if (fleetId) {
    conditions.push(eq(fleets.id, fleetId));
  }
  if (depotId) {
    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
  }

  // Query with joins
  const results = await db
    .select({
      trainNumber: trains.trainNumber,
      fleetCode: fleets.code,
      pmCode: pmTypes.pmCode,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      constraintStart: pmSchedule.constraintStart,
      constraintEnd: pmSchedule.constraintEnd,
      assignedDepot: depots.name,
      assignedTrack: tracks.trackNumber,
      estimatedHours: pmTypes.estimatedHours,
      maximoWoId: pmSchedule.maximoWoId,
      isLocked: pmSchedule.isLocked,
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
    .where(and(...conditions))
    .orderBy(asc(pmSchedule.targetDate), asc(trains.trainNumber));

  const rows: PmScheduleRow[] = results.map((r) => ({
    trainNumber: r.trainNumber,
    fleetCode: r.fleetCode,
    pmCode: r.pmCode,
    targetDate: r.targetDate,
    status: r.status ?? 'SCHEDULED', // Default to SCHEDULED if null
    constraintStart: r.constraintStart,
    constraintEnd: r.constraintEnd,
    assignedDepot: r.assignedDepot,
    assignedTrack: r.assignedTrack,
    estimatedHours: r.estimatedHours ? Number(r.estimatedHours) : null,
    maximoWoId: r.maximoWoId,
    isLocked: r.isLocked ?? false, // Default to false if null
  }));

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'pm_schedule',
      columns: [
        'trainNumber', 'fleetCode', 'pmCode', 'targetDate', 'status',
        'constraintStart', 'constraintEnd', 'assignedDepot', 'assignedTrack',
        'estimatedHours', 'maximoWoId', 'isLocked',
      ],
      generatedAt: new Date().toISOString(),
      filters: { startDate, endDate, fleetId, depotId, status: statusFilter },
    },
  };
}

/**
 * Fetch fleet status data using FleetService
 */
async function fetchFleetStatusData(filters?: Record<string, unknown>): Promise<ReportData> {
  const fleetService = getFleetService();

  // Get all fleet statistics
  const allStats = await fleetService.getAllFleetStatistics();

  // Optionally filter by fleetId
  const fleetId = filters?.['fleetId'] as string | undefined;
  const filteredStats = fleetId
    ? allStats.filter((s) => s.fleetId === fleetId || s.fleetCode === fleetId)
    : allStats;

  const rows: FleetStatusRow[] = filteredStats.map((s: FleetStatistics) => ({
    fleetCode: s.fleetCode,
    fleetName: s.fleetCode, // FleetStatistics has fleetCode but not fleetName
    totalTrains: s.totalTrains,
    fitTrains: s.fitTrains,
    restrictedTrains: s.restrictedTrains,
    groundedTrains: s.groundedTrains,
    avgMileageKm: Math.round(s.averageMileageKm),
    minMileageKm: s.minMileageKm,
    maxMileageKm: s.maxMileageKm,
    stdDevMileageKm: Math.round(s.mileageStdDevKm),
  }));

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'fleet_status',
      columns: [
        'fleetCode', 'fleetName', 'totalTrains', 'fitTrains', 'restrictedTrains',
        'groundedTrains', 'avgMileageKm', 'minMileageKm', 'maxMileageKm', 'stdDevMileageKm',
      ],
      generatedAt: new Date().toISOString(),
      filters: { fleetId },
    },
  };
}

/**
 * Fetch drift report data using DriftMonitorService
 */
async function fetchDriftReportData(filters?: Record<string, unknown>): Promise<ReportData> {
  const driftService = getDriftMonitorService();

  // Run or get latest drift analysis
  const analysisDate = filters?.['analysisDate'] as string | undefined;
  const analysisDateObj = analysisDate ? new Date(analysisDate) : undefined;
  const result: DriftAnalysisResult = await driftService.runDriftAnalysis(analysisDateObj);

  // Check if analysis was skipped (discriminated union check)
  if (result.skipped) {
    return {
      rowCount: 0,
      data: [],
      metadata: {
        reportType: 'drift_report',
        status: 'SKIPPED',
        reason: result.reason,
        generatedAt: new Date().toISOString(),
        filters,
      },
    };
  }

  // Type narrowing - result is now DriftAnalysisSuccess
  const successResult = result as DriftAnalysisSuccess;

  // Extract train analyses
  const trainAnalyses = successResult.trainAnalyses;

  const rows: DriftReportRow[] = trainAnalyses.map((t: TrainDriftAnalysis) => ({
    trainNumber: t.trainNumber,
    fleetCode: '', // TrainDriftAnalysis doesn't have fleetCode; would need separate lookup
    baselineProjectedKm: t.baselineProjectedKm,
    actualKm: t.actualKm,
    mileageDriftPct: t.mileageDriftPct,
    avgPmDriftDays: t.avgPmDriftDays,
    maxPmDriftDays: t.maxPmDriftDays,
    requiresReplan: t.requiresReplan,
    replanReason: t.replanReason ?? null,
  }));

  // Get summary and alerts
  const summary = successResult.summary;
  const alerts = successResult.alerts;

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'drift_report',
      baselineId: successResult.baselineId,
      analysisDate: successResult.analysisDate,
      summary: {
        totalTrainsAnalyzed: summary.totalTrains,
        trainsRequiringReplan: summary.trainsRequiringReplan,
        avgMileageDriftPct: summary.avgFleetDriftPct,
        maxPmDriftDays: 0, // Not directly available in summary, would need to calculate
      },
      alerts: alerts.map((a: DriftAlert) => ({
        severity: a.severity,
        type: a.type,
        message: a.message,
        trainNumber: a.trainNumber,
      })),
      columns: [
        'trainNumber', 'fleetCode', 'baselineProjectedKm', 'actualKm', 'mileageDriftPct',
        'avgPmDriftDays', 'maxPmDriftDays', 'requiresReplan', 'replanReason',
      ],
      generatedAt: new Date().toISOString(),
      filters,
    },
  };
}

/**
 * Fetch TCO projection data using CostingService
 */
async function fetchTcoProjectionData(filters?: Record<string, unknown>): Promise<ReportData> {
  const costingService = getCostingService();

  // Parse filters - ProjectTCORequest only has horizonYears, scenarioId, depotId
  const horizonYears = (filters?.['horizonYears'] as number) ?? 12;
  const depotId = filters?.['depotId'] as string | undefined;
  const scenarioId = filters?.['scenarioId'] as string | undefined;

  // Project TCO
  const projection: TCOProjection = await costingService.projectTCO({
    horizonYears,
    depotId,
    scenarioId,
  });

  // Calculate overhead as 18% of (labor + material) for each year
  const OVERHEAD_RATE = 0.18;
  const rows: TcoProjectionRow[] = projection.projections.map((p: YearlyCost) => {
    const overheadCost = (p.laborCost + p.materialCost) * OVERHEAD_RATE;
    return {
      fiscalYear: p.fiscalYear,
      laborCost: p.laborCost,
      materialCost: p.materialCost,
      overheadCost: Math.round(overheadCost),
      totalCost: p.totalCost,
      pmCount: p.pmCount,
      inflationFactor: p.inflationFactor,
    };
  });

  // Calculate total overhead cost from the rows
  const totalOverheadCost = rows.reduce((sum, r) => sum + r.overheadCost, 0);

  return {
    rowCount: rows.length,
    data: rows as unknown as Record<string, unknown>[],
    metadata: {
      reportType: 'tco_projection',
      horizonYears,
      summary: {
        totalLaborCost: projection.summary.totalLaborCost,
        totalMaterialCost: projection.summary.totalMaterialCost,
        totalOverheadCost: totalOverheadCost,
        grandTotal: projection.summary.totalCost,
        npv: projection.summary.npv,
        avgAnnualCost: projection.summary.avgAnnualCost,
      },
      columns: [
        'fiscalYear', 'laborCost', 'materialCost', 'overheadCost', 'totalCost',
        'pmCount', 'inflationFactor',
      ],
      generatedAt: new Date().toISOString(),
      filters: { horizonYears, depotId, scenarioId },
    },
  };
}

// =============================================================================
// Excel Generation
// =============================================================================

/**
 * Generate Excel report using ExcelJS
 */
async function generateExcelReport(
  jobId: string,
  type: string,
  reportData: ReportData
): Promise<ReportResult> {
  return withSpan('report.generateExcel', async (span) => {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const fileName = `${type}_${timestamp}.xlsx`;
    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);

    span.setAttribute('report.fileName', fileName);
    span.setAttribute('report.filePath', filePath);

    // Create workbook and worksheet
    const workbook = new ExcelJS.Workbook();
    workbook.creator = 'MMS Report Generator';
    workbook.created = new Date();

    const worksheet = workbook.addWorksheet(formatReportTitle(type));

    // Get columns from metadata
    const columns = (reportData.metadata['columns'] as string[]) ?? [];

    // Configure columns with headers and widths
    worksheet.columns = columns.map((col) => ({
      header: formatColumnHeader(col),
      key: col,
      width: getColumnWidth(col),
    }));

    // Style header row
    const headerRow = worksheet.getRow(1);
    headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
    headerRow.fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: 'FF2E5A88' }, // MMS blue
    };
    headerRow.alignment = { vertical: 'middle', horizontal: 'center' };

    // Add data rows
    reportData.data.forEach((row) => {
      const rowData: Record<string, unknown> = {};
      columns.forEach((col) => {
        rowData[col] = formatCellValue(row[col], col);
      });
      worksheet.addRow(rowData);
    });

    // Apply alternating row colors
    worksheet.eachRow((row, rowNumber) => {
      if (rowNumber > 1 && rowNumber % 2 === 0) {
        row.fill = {
          type: 'pattern',
          pattern: 'solid',
          fgColor: { argb: 'FFF5F5F5' },
        };
      }
    });

    // Add filters to first row if supported
    if (reportData.rowCount > 0) {
      worksheet.autoFilter = {
        from: { row: 1, column: 1 },
        to: { row: 1, column: columns.length },
      };
    }

    // Add metadata sheet
    const metaSheet = workbook.addWorksheet('Report Info');
    metaSheet.addRow(['Report Type', formatReportTitle(type)]);
    metaSheet.addRow(['Generated At', reportData.metadata['generatedAt']]);
    metaSheet.addRow(['Total Records', reportData.rowCount]);

    // Add summary data for specific report types
    if (type === 'tco_projection' && reportData.metadata['summary']) {
      const summary = reportData.metadata['summary'] as Record<string, number>;
      metaSheet.addRow([]);
      metaSheet.addRow(['TCO Summary']);
      metaSheet.addRow(['Total Labor Cost', formatCurrency(summary['totalLaborCost'])]);
      metaSheet.addRow(['Total Material Cost', formatCurrency(summary['totalMaterialCost'])]);
      metaSheet.addRow(['Total Overhead Cost', formatCurrency(summary['totalOverheadCost'])]);
      metaSheet.addRow(['Grand Total', formatCurrency(summary['grandTotal'])]);
      metaSheet.addRow(['NPV', formatCurrency(summary['npv'])]);
      metaSheet.addRow(['Average Annual Cost', formatCurrency(summary['avgAnnualCost'])]);
    }

    if (type === 'drift_report' && reportData.metadata['summary']) {
      const summary = reportData.metadata['summary'] as Record<string, number>;
      metaSheet.addRow([]);
      metaSheet.addRow(['Drift Analysis Summary']);
      metaSheet.addRow(['Total Trains Analyzed', summary['totalTrainsAnalyzed']]);
      metaSheet.addRow(['Trains Requiring Replan', summary['trainsRequiringReplan']]);
      metaSheet.addRow(['Average Mileage Drift %', `${summary['avgMileageDriftPct']?.toFixed(2)}%`]);
      metaSheet.addRow(['Maximum PM Drift Days', summary['maxPmDriftDays']]);
    }

    metaSheet.columns = [
      { width: 25 },
      { width: 30 },
    ];

    // Write to file
    await workbook.xlsx.writeFile(filePath);

    const stats = await fs.stat(filePath);
    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);

    return {
      jobId,
      type,
      format: 'excel',
      filePath,
      fileName,
      fileSizeBytes: stats.size,
      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
      expiresAt,
      generatedAt: new Date(),
      rowCount: reportData.rowCount,
    };
  });
}

/**
 * Get appropriate column width based on column name
 */
function getColumnWidth(col: string): number {
  const widths: Record<string, number> = {
    trainNumber: 12,
    fleetCode: 10,
    fleetName: 20,
    pmCode: 8,
    targetDate: 12,
    status: 12,
    constraintStart: 14,
    constraintEnd: 14,
    assignedDepot: 15,
    assignedTrack: 12,
    estimatedHours: 14,
    maximoWoId: 15,
    isLocked: 8,
    totalTrains: 12,
    fitTrains: 10,
    restrictedTrains: 14,
    groundedTrains: 14,
    avgMileageKm: 14,
    minMileageKm: 12,
    maxMileageKm: 12,
    stdDevMileageKm: 14,
    baselineProjectedKm: 18,
    actualKm: 12,
    mileageDriftPct: 14,
    avgPmDriftDays: 14,
    maxPmDriftDays: 14,
    requiresReplan: 14,
    replanReason: 25,
    fiscalYear: 12,
    laborCost: 14,
    materialCost: 14,
    overheadCost: 14,
    totalCost: 14,
    pmCount: 10,
    inflationFactor: 14,
  };
  return widths[col] ?? 15;
}

/**
 * Format column header from camelCase to Title Case
 */
function formatColumnHeader(col: string): string {
  return col
    .replace(/([A-Z])/g, ' $1')
    .replace(/^./, (str) => str.toUpperCase())
    .replace(/Km/g, '(km)')
    .replace(/Pct/g, '(%)')
    .trim();
}

/**
 * Format cell value for display
 */
function formatCellValue(value: unknown, col: string): string | number | boolean | Date | null {
  if (value === null || value === undefined) return '';

  // Currency columns
  if (['laborCost', 'materialCost', 'overheadCost', 'totalCost'].includes(col)) {
    return typeof value === 'number' ? value : parseFloat(String(value)) || 0;
  }

  // Percentage columns
  if (col.includes('Pct')) {
    return typeof value === 'number' ? `${value.toFixed(2)}%` : String(value);
  }

  // Boolean columns
  if (typeof value === 'boolean') {
    return value ? 'Yes' : 'No';
  }

  // Date columns
  if (col.includes('Date') && typeof value === 'string') {
    return value;
  }

  return value as string | number | boolean | Date;
}

/**
 * Format currency value
 */
function formatCurrency(value: number | undefined): string {
  if (value === undefined) return 'N/A';
  return new Intl.NumberFormat('en-SG', {
    style: 'currency',
    currency: 'SGD',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
}

// =============================================================================
// PDF Generation
// =============================================================================

// Define fonts for pdfmake (using Roboto which comes bundled)
const fonts = {
  Roboto: {
    normal: 'node_modules/pdfmake/build/vfs_fonts.js',
    bold: 'node_modules/pdfmake/build/vfs_fonts.js',
    italics: 'node_modules/pdfmake/build/vfs_fonts.js',
    bolditalics: 'node_modules/pdfmake/build/vfs_fonts.js',
  },
};

/**
 * Generate PDF report using pdfmake
 */
async function generatePdfReport(
  jobId: string,
  type: string,
  reportData: ReportData
): Promise<ReportResult> {
  return withSpan('report.generatePdf', async (span) => {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const fileName = `${type}_${timestamp}.pdf`;
    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);

    span.setAttribute('report.fileName', fileName);
    span.setAttribute('report.filePath', filePath);

    // Create PDF document definition
    const docDefinition = createPdfDocDefinition(type, reportData);

    // Create PDF printer
    const printer = new PdfPrinter(fonts);
    const pdfDoc = printer.createPdfKitDocument(docDefinition);

    // Write to file using synchronous fs createWriteStream
    await new Promise<void>((resolve, reject) => {
      const writeStream = fsSync.createWriteStream(filePath);
      pdfDoc.pipe(writeStream);
      pdfDoc.end();
      writeStream.on('finish', resolve);
      writeStream.on('error', reject);
    });

    const stats = await fs.stat(filePath);
    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);

    // Estimate page count (roughly 40 rows per page in landscape)
    const estimatedPageCount = Math.max(1, Math.ceil(reportData.rowCount / 40));

    return {
      jobId,
      type,
      format: 'pdf',
      filePath,
      fileName,
      fileSizeBytes: stats.size,
      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
      expiresAt,
      generatedAt: new Date(),
      rowCount: reportData.rowCount,
      pageCount: estimatedPageCount,
    };
  });
}

/**
 * Create PDF document definition for pdfmake
 */
function createPdfDocDefinition(type: string, reportData: ReportData): TDocumentDefinitions {
  const columns = (reportData.metadata['columns'] as string[]) ?? [];
  const generatedAt = reportData.metadata['generatedAt'] as string;

  // Build content array
  const content: Content[] = [];

  // Header
  content.push({
    text: `MMS ${formatReportTitle(type)}`,
    style: 'header',
    margin: [0, 0, 0, 10],
  });

  // Report info
  content.push({
    text: [
      { text: 'Generated: ', bold: true },
      format(new Date(generatedAt), 'PPpp'),
      '  |  ',
      { text: 'Records: ', bold: true },
      String(reportData.rowCount),
    ],
    style: 'subheader',
    margin: [0, 0, 0, 15],
  });

  // Add summary section for specific report types
  if (type === 'tco_projection' && reportData.metadata['summary']) {
    content.push(createTcoSummaryContent(reportData.metadata['summary'] as Record<string, number>));
  }

  if (type === 'drift_report' && reportData.metadata['summary']) {
    content.push(createDriftSummaryContent(
      reportData.metadata['summary'] as Record<string, number>,
      reportData.metadata['alerts'] as Array<{ severity: string; message: string }> | undefined
    ));
  }

  if (type === 'fleet_status') {
    content.push(createFleetSummaryContent(reportData.data as unknown as FleetStatusRow[]));
  }

  // Data table
  if (reportData.rowCount > 0 && columns.length > 0) {
    content.push({
      text: 'Detailed Data',
      style: 'sectionHeader',
      margin: [0, 20, 0, 10],
    });

    content.push(createDataTable(columns, reportData.data));
  } else {
    content.push({
      text: 'No data available for the specified filters.',
      style: 'noData',
      margin: [0, 20, 0, 0],
    });
  }

  // Footer with page numbers
  return {
    pageSize: 'A4',
    pageOrientation: 'landscape',
    pageMargins: [40, 60, 40, 60],
    header: (currentPage: number, pageCount: number) => ({
      columns: [
        { text: 'MMS Report', style: 'pageHeader' },
        { text: `Page ${currentPage} of ${pageCount}`, style: 'pageHeader', alignment: 'right' },
      ],
      margin: [40, 20, 40, 10],
    }),
    footer: () => ({
      text: 'Metro Fleet Mileage Management System - Confidential',
      style: 'footer',
      alignment: 'center',
      margin: [40, 10, 40, 20],
    }),
    content,
    styles: {
      header: {
        fontSize: 18,
        bold: true,
        color: '#2E5A88',
      },
      subheader: {
        fontSize: 10,
        color: '#666666',
      },
      sectionHeader: {
        fontSize: 14,
        bold: true,
        color: '#2E5A88',
      },
      tableHeader: {
        bold: true,
        fontSize: 8,
        color: 'white',
        fillColor: '#2E5A88',
      },
      tableCell: {
        fontSize: 7,
      },
      tableCellAlt: {
        fontSize: 7,
        fillColor: '#F5F5F5',
      },
      summaryLabel: {
        fontSize: 10,
        bold: true,
      },
      summaryValue: {
        fontSize: 10,
      },
      alertCritical: {
        fontSize: 9,
        color: '#D32F2F',
      },
      alertHigh: {
        fontSize: 9,
        color: '#F57C00',
      },
      alertMedium: {
        fontSize: 9,
        color: '#FBC02D',
      },
      noData: {
        fontSize: 12,
        italics: true,
        color: '#999999',
      },
      pageHeader: {
        fontSize: 8,
        color: '#999999',
      },
      footer: {
        fontSize: 8,
        color: '#999999',
      },
    },
    defaultStyle: {
      font: 'Roboto',
    },
  };
}

/**
 * Create data table for PDF
 */
function createDataTable(columns: string[], data: Record<string, unknown>[]): Content {
  // Limit columns displayed based on page width
  const displayColumns = columns.slice(0, 10);

  // Header row
  const headerRow: TableCell[] = displayColumns.map((col) => ({
    text: formatColumnHeader(col),
    style: 'tableHeader',
    alignment: 'center',
  }));

  // Data rows
  const dataRows: TableCell[][] = data.map((row, index) =>
    displayColumns.map((col) => ({
      text: String(formatCellValue(row[col], col) ?? ''),
      style: index % 2 === 0 ? 'tableCell' : 'tableCellAlt',
      alignment: isNumericColumn(col) ? 'right' : 'left',
    }))
  );

  // Calculate column widths (equal distribution)
  const colWidth = (842 - 80) / displayColumns.length; // A4 landscape width minus margins
  const widths = displayColumns.map(() => colWidth);

  return {
    table: {
      headerRows: 1,
      widths,
      body: [headerRow, ...dataRows],
    },
    layout: {
      hLineWidth: () => 0.5,
      vLineWidth: () => 0.5,
      hLineColor: () => '#DDDDDD',
      vLineColor: () => '#DDDDDD',
      paddingLeft: () => 4,
      paddingRight: () => 4,
      paddingTop: () => 2,
      paddingBottom: () => 2,
    },
  };
}

/**
 * Check if column contains numeric data
 */
function isNumericColumn(col: string): boolean {
  const numericCols = [
    'totalTrains', 'fitTrains', 'restrictedTrains', 'groundedTrains',
    'avgMileageKm', 'minMileageKm', 'maxMileageKm', 'stdDevMileageKm',
    'baselineProjectedKm', 'actualKm', 'mileageDriftPct', 'avgPmDriftDays',
    'maxPmDriftDays', 'fiscalYear', 'laborCost', 'materialCost',
    'overheadCost', 'totalCost', 'pmCount', 'inflationFactor', 'estimatedHours',
  ];
  return numericCols.includes(col);
}

/**
 * Create TCO summary content for PDF
 */
function createTcoSummaryContent(summary: Record<string, number>): Content {
  return {
    columns: [
      {
        width: '50%',
        stack: [
          { text: 'TCO Summary', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'Total Labor Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalLaborCost']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Total Material Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalMaterialCost']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Total Overhead Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalOverheadCost']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Grand Total:', style: 'summaryLabel', bold: true }, { text: formatCurrency(summary['grandTotal']), style: 'summaryValue', alignment: 'right', bold: true }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
      {
        width: '50%',
        stack: [
          { text: 'Financial Metrics', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'Net Present Value (NPV):', style: 'summaryLabel' }, { text: formatCurrency(summary['npv']), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Average Annual Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['avgAnnualCost']), style: 'summaryValue', alignment: 'right' }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
    ],
    margin: [0, 0, 0, 20],
  };
}

/**
 * Create drift summary content for PDF
 */
function createDriftSummaryContent(
  summary: Record<string, number>,
  alerts?: Array<{ severity: string; message: string }>
): Content {
  const content: Content[] = [
    {
      columns: [
        {
          width: '50%',
          stack: [
            { text: 'Drift Analysis Summary', style: 'sectionHeader', margin: [0, 0, 0, 10] },
            {
              table: {
                widths: ['*', 'auto'],
                body: [
                  [{ text: 'Total Trains Analyzed:', style: 'summaryLabel' }, { text: String(summary['totalTrainsAnalyzed']), style: 'summaryValue', alignment: 'right' }],
                  [{ text: 'Trains Requiring Replan:', style: 'summaryLabel' }, { text: String(summary['trainsRequiringReplan']), style: 'summaryValue', alignment: 'right' }],
                  [{ text: 'Average Mileage Drift:', style: 'summaryLabel' }, { text: `${summary['avgMileageDriftPct']?.toFixed(2)}%`, style: 'summaryValue', alignment: 'right' }],
                  [{ text: 'Maximum PM Drift:', style: 'summaryLabel' }, { text: `${summary['maxPmDriftDays']} days`, style: 'summaryValue', alignment: 'right' }],
                ],
              },
              layout: 'noBorders',
            },
          ],
        },
      ],
      margin: [0, 0, 0, 10],
    },
  ];

  // Add alerts if present
  if (alerts && alerts.length > 0) {
    content.push({
      text: 'Active Alerts',
      style: 'sectionHeader',
      margin: [0, 10, 0, 5],
    });

    const alertList = alerts.slice(0, 5).map((alert) => ({
      text: `• ${alert.message}`,
      style: alert.severity === 'CRITICAL' ? 'alertCritical' :
             alert.severity === 'HIGH' ? 'alertHigh' : 'alertMedium',
      margin: [0, 2, 0, 2] as [number, number, number, number],
    }));

    content.push({
      stack: alertList,
      margin: [10, 0, 0, 10],
    } as Content);
  }

  return {
    stack: content,
    margin: [0, 0, 0, 20],
  };
}

/**
 * Create fleet summary content for PDF
 */
function createFleetSummaryContent(data: FleetStatusRow[]): Content {
  const totalTrains = data.reduce((sum, r) => sum + r.totalTrains, 0);
  const totalFit = data.reduce((sum, r) => sum + r.fitTrains, 0);
  const totalRestricted = data.reduce((sum, r) => sum + r.restrictedTrains, 0);
  const totalGrounded = data.reduce((sum, r) => sum + r.groundedTrains, 0);

  return {
    columns: [
      {
        width: '50%',
        stack: [
          { text: 'Fleet Overview', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'Total Fleets:', style: 'summaryLabel' }, { text: String(data.length), style: 'summaryValue', alignment: 'right' }],
                [{ text: 'Total Trains:', style: 'summaryLabel' }, { text: String(totalTrains), style: 'summaryValue', alignment: 'right' }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
      {
        width: '50%',
        stack: [
          { text: 'Fitness Status', style: 'sectionHeader', margin: [0, 0, 0, 10] },
          {
            table: {
              widths: ['*', 'auto'],
              body: [
                [{ text: 'FIT:', style: 'summaryLabel' }, { text: `${totalFit} (${((totalFit / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
                [{ text: 'RESTRICTED:', style: 'summaryLabel' }, { text: `${totalRestricted} (${((totalRestricted / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
                [{ text: 'GROUNDED:', style: 'summaryLabel' }, { text: `${totalGrounded} (${((totalGrounded / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
              ],
            },
            layout: 'noBorders',
          },
        ],
      },
    ],
    margin: [0, 0, 0, 20],
  };
}

// =============================================================================
// Utilities
// =============================================================================

/**
 * Ensure output directory exists
 */
async function ensureOutputDir(): Promise<void> {
  try {
    await fs.access(REPORTS_OUTPUT_DIR);
  } catch {
    await fs.mkdir(REPORTS_OUTPUT_DIR, { recursive: true });
    log.info({ dir: REPORTS_OUTPUT_DIR }, 'Created reports output directory');
  }
}

/**
 * Format file size for display
 */
function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

/**
 * Format report type as human-readable title
 */
function formatReportTitle(type: string): string {
  const titles: Record<string, string> = {
    pm_schedule: 'PM Schedule Export',
    fleet_status: 'Fleet Status Report',
    drift_report: 'Drift Analysis Report',
    tco_projection: 'TCO Projection Report',
  };
  return titles[type] ?? type;
}

/**
 * Register the report worker
 */
export function registerReportWorker(): void {
  log.info('Report worker processor available for registration');
}

