   132→  deduplicateWithWebhooks?: boolean;
   133→}
   134→
   135→export type JobData =
   136→  | IngestionJobData
   137→  | TacticalSchedulerJobData
   138→  | StrategicPlannerJobData
   139→  | OptimizerJobData
   140→  | ManhourLevelingJobData
   141→  | DriftMonitorJobData
   142→  | NotificationJobData
   143→  | ReportJobData
   144→  | MaximoSyncJobData;
   145→
   146→// =============================================================================
   147→// Default Job Options
   148→// =============================================================================
   149→
   150→const DEFAULT_JOB_OPTIONS: JobsOptions = {
   151→  attempts: 3,
   152→  backoff: {
   153→    type: 'exponential',
   154→    delay: 1000,
   155→  },
   156→  removeOnComplete: {
   157→    age: 24 * 3600,
   158→    count: 1000,
