/**
 * MMS Queue Configuration
 *
 * BullMQ queue setup for background job processing.
 * All queue operations go through Redis for distributed processing.
 *
 * Queue types:
 * - ingestion: CSV file processing and mileage data import
 * - tactical_scheduler: PM scheduling within 12-week horizon
 * - strategic_planner: Long-term (10-year) PM planning
 * - optimizer: Run assignment optimization (CP-SAT)
 * - manhour_leveling: Workload balancing across periods
 * - drift_monitor: Baseline comparison and drift detection
 * - notification: Email and alert sending
 * - report: PDF/Excel report generation
 *
 * @see specs/004-backend-specification.md Section 4.8
 */

import { Queue, Worker, QueueEvents, type JobsOptions, type WorkerOptions } from 'bullmq';

// =============================================================================
// Queue Names
// =============================================================================

export const QUEUE_NAMES = {
  INGESTION: 'mms:ingestion',
  TACTICAL_SCHEDULER: 'mms:tactical-scheduler',
  STRATEGIC_PLANNER: 'mms:strategic-planner',
  OPTIMIZER: 'mms:optimizer',
  MANHOUR_LEVELING: 'mms:manhour-leveling',
  DRIFT_MONITOR: 'mms:drift-monitor',
  NOTIFICATION: 'mms:notification',
  REPORT: 'mms:report',
  MAXIMO_SYNC: 'mms:maximo-sync',
} as const;

export type QueueName = (typeof QUEUE_NAMES)[keyof typeof QUEUE_NAMES];

// =============================================================================
// Redis Configuration
// =============================================================================

function getRedisConfig() {
  return {
    host: process.env['REDIS_HOST'] ?? 'localhost',
    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
    password: process.env['REDIS_PASSWORD'],
    maxRetriesPerRequest: null as null, // Required for BullMQ
  };
}

// =============================================================================
// Job Types
// =============================================================================

export interface IngestionJobData {
  filePath: string;
  fileName: string;
  fileSize: number;
  uploadedBy?: string;
}

export interface TacticalSchedulerJobData {
  fleetId?: string;
  trainIds?: string[];
  horizonWeeks?: number;
  dryRun?: boolean;
}

export interface StrategicPlannerJobData {
  fleetId?: string;
  horizonYears?: number;
  populationSize?: number;
  generations?: number;
}

export interface OptimizerJobData {
  date: string;
  fleetId: string;
  constraints?: {
    serviceRequirements?: Record<string, number>;
    unavailableTrains?: string[];
    preferredAssignments?: Record<string, string>;
  };
  timeoutMs?: number;
}

export interface ManhourLevelingJobData {
  depotId?: string;
  periodStart: string;
  periodEnd: string;
  strategies?: string[];
}

export interface DriftMonitorJobData {
  baselineId: string;
  trainIds?: string[];
}

export interface NotificationJobData {
  type: 'email' | 'webhook';
  template: string;
  recipients: string[];
  data: Record<string, unknown>;
  priority?: 'high' | 'normal' | 'low';
}

export interface ReportJobData {
  type: 'pm_schedule' | 'fleet_status' | 'drift_report' | 'tco_projection';
  format: 'pdf' | 'excel';
  filters?: Record<string, unknown>;
  requestedBy: string;
}

export interface MaximoSyncJobData {
  /** Sync operation: push, pull, full (both), or polling (scheduled pull) */
  operation: 'push' | 'pull' | 'full' | 'polling';
  /** Optional: specific PM schedule IDs to sync (push only) */
  pmScheduleIds?: string[];
  /** Optional: depot ID to limit sync scope */
  depotId?: string;
  /** Force sync even if recently synced */
  force?: boolean;
  /** Conflict resolution strategy (must match ConflictResolution type from maximo-sync service) */
  conflictResolution?: 'USE_MMS' | 'USE_MAXIMO';
  /** Polling-specific: triggered by webhook timeout fallback */
  isPollingFallback?: boolean;
  /** Polling-specific: modified since timestamp for incremental queries */
  modifiedSince?: string;
  /** Polling-specific: enable deduplication against recent webhooks */
  deduplicateWithWebhooks?: boolean;
}

export type JobData =
  | IngestionJobData
  | TacticalSchedulerJobData
  | StrategicPlannerJobData
  | OptimizerJobData
  | ManhourLevelingJobData
  | DriftMonitorJobData
  | NotificationJobData
  | ReportJobData
  | MaximoSyncJobData;

// =============================================================================
// Default Job Options
// =============================================================================

const DEFAULT_JOB_OPTIONS: JobsOptions = {
  attempts: 3,
  backoff: {
    type: 'exponential',
    delay: 1000,
  },
  removeOnComplete: {
    age: 24 * 3600,
    count: 1000,
  },
  removeOnFail: {
    age: 7 * 24 * 3600,
  },
};

// =============================================================================
// Queue Factory
// =============================================================================

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const queues: Map<QueueName, Queue<any>> = new Map();
const queueEvents: Map<QueueName, QueueEvents> = new Map();

/**
 * Get or create a queue instance
 */
export function getQueue(name: QueueName): Queue {
  if (!queues.has(name)) {
    const queue = new Queue(name, {
      connection: getRedisConfig(),
      defaultJobOptions: DEFAULT_JOB_OPTIONS,
    });
    queues.set(name, queue);
  }
  return queues.get(name)!;
}

/**
 * Get queue events for monitoring
 */
export function getQueueEvents(name: QueueName): QueueEvents {
  if (!queueEvents.has(name)) {
    const events = new QueueEvents(name, { connection: getRedisConfig() });
    queueEvents.set(name, events);
  }
  return queueEvents.get(name)!;
}

// =============================================================================
// Worker Factory
// =============================================================================

export interface JobContext<T = unknown> {
  id?: string;
  name: string;
  data: T;
}

/**
 * Create a worker for processing jobs
 */
export function createWorker<T = JobData>(
  name: QueueName,
  processor: (job: JobContext<T>) => Promise<unknown>,
  options?: Partial<WorkerOptions>
): Worker {
  const workerOptions: WorkerOptions = {
    connection: getRedisConfig(),
    concurrency: 1,
    ...options,
  };

  return new Worker(
    name,
    async (job) => {
      return processor({
        id: job.id,
        name: job.name,
        data: job.data as T,
      });
    },
    workerOptions
  );
}

// =============================================================================
// Job Utilities
// =============================================================================

/**
 * Add a job to a queue
 */
export async function addJob<T = JobData>(
  queueName: QueueName,
  jobName: string,
  data: T,
  options?: Partial<JobsOptions>
): Promise<{ id: string }> {
  const queue = getQueue(queueName);
  const job = await queue.add(jobName, data, options);
  return { id: job.id! };
}

/**
 * Add multiple jobs to a queue
 */
export async function addBulkJobs<T = JobData>(
  queueName: QueueName,
  jobs: Array<{ name: string; data: T; opts?: Partial<JobsOptions> }>
): Promise<Array<{ id: string }>> {
  const queue = getQueue(queueName);
  const results = await queue.addBulk(jobs);
  return results.map((job) => ({ id: job.id! }));
}

/**
 * Get job by ID
 */
export async function getJob<T = JobData>(
  queueName: QueueName,
  jobId: string
): Promise<{ id: string; data: T; status: string } | null> {
  const queue = getQueue(queueName);
  const job = await queue.getJob(jobId);
  if (!job) return null;

  const state = await job.getState();
  return {
    id: job.id!,
    data: job.data as T,
    status: state,
  };
}

/**
 * Get queue statistics
 */
export async function getQueueStats(queueName: QueueName): Promise<{
  waiting: number;
  active: number;
  completed: number;
  failed: number;
  delayed: number;
}> {
  const queue = getQueue(queueName);
  const [waiting, active, completed, failed, delayed] = await Promise.all([
    queue.getWaitingCount(),
    queue.getActiveCount(),
    queue.getCompletedCount(),
    queue.getFailedCount(),
    queue.getDelayedCount(),
  ]);
  return { waiting, active, completed, failed, delayed };
}

// =============================================================================
// Cleanup
// =============================================================================

/**
 * Close all queue connections
 */
export async function closeAllQueues(): Promise<void> {
  const closePromises: Promise<void>[] = [];

  for (const queue of queues.values()) {
    closePromises.push(queue.close());
  }

  for (const events of queueEvents.values()) {
    closePromises.push(events.close());
  }

  await Promise.all(closePromises);
  queues.clear();
  queueEvents.clear();
}

// =============================================================================
// Progress Streaming
// =============================================================================

export interface JobProgress {
  percent: number;
  stage?: string;
  message?: string;
  details?: Record<string, unknown>;
}

/**
 * Stream job progress updates via callback
 */
export function streamJobProgress(
  queueName: QueueName,
  jobId: string,
  onProgress: (progress: unknown) => void,
  onComplete: (result: unknown) => void,
  onError: (error: Error) => void
): () => void {
  const events = getQueueEvents(queueName);

  const progressHandler = (args: { jobId: string; data: unknown }) => {
    if (args.jobId === jobId) {
      onProgress(args.data);
    }
  };

  const completedHandler = (args: { jobId: string; returnvalue: unknown }) => {
    if (args.jobId === jobId) {
      onComplete(args.returnvalue);
      cleanup();
    }
  };

  const failedHandler = (args: { jobId: string; failedReason: string }) => {
    if (args.jobId === jobId) {
      onError(new Error(args.failedReason));
      cleanup();
    }
  };

  events.on('progress', progressHandler);
  events.on('completed', completedHandler);
  events.on('failed', failedHandler);

  const cleanup = () => {
    events.off('progress', progressHandler);
    events.off('completed', completedHandler);
    events.off('failed', failedHandler);
  };

  return cleanup;
}

