     1→/**
     2→ * MMS File Watcher Daemon
     3→ *
     4→ * Monitors a directory for new mileage CSV files and queues them for processing.
     5→ * Uses chokidar for cross-platform file system watching.
     6→ *
     7→ * Usage:
     8→ *   bun run src/file-watcher/daemon.ts
     9→ *
    10→ * Environment Variables:
    11→ *   WATCH_PATH - Directory to watch for new files (default: /data/inbox)
    12→ *   QUARANTINE_PATH - Directory for failed files (default: /data/quarantine)
    13→ *   POLL_INTERVAL_MS - Polling interval in ms (default: 1000)
    14→ *   FILE_PATTERN - Regex pattern for files to process (default: mileage_\\d{8}\\.csv)
    15→ *
    16→ * @see specs/004-domain-services.md Section 4.2
    17→ * @see specs/008-operations.md
    18→ */
    19→
    20→import * as chokidar from 'chokidar';
    21→import * as fs from 'node:fs';
    22→import * as path from 'node:path';
    23→import { logger } from '../lib/logging/logger';
    24→import { addJob, QUEUE_NAMES } from '../lib/queue';
    25→import type { IngestionJobData } from '../lib/queue';
    26→
    27→// =============================================================================
    28→// Configuration
    29→// =============================================================================
    30→
    31→interface FileWatcherConfig {
    32→  watchPath: string;
    33→  quarantinePath: string;
    34→  pollIntervalMs: number;
    35→  filePattern: RegExp;
    36→  stabilityThresholdMs: number;
    37→}
    38→
    39→function getConfig(): FileWatcherConfig {
    40→  const watchPath = process.env['WATCH_PATH'] || '/data/inbox';
    41→  const quarantinePath = process.env['QUARANTINE_PATH'] || '/data/quarantine';
    42→  const pollIntervalMs = parseInt(process.env['POLL_INTERVAL_MS'] || '1000', 10);
    43→  const filePatternStr = process.env['FILE_PATTERN'] || 'mileage_\\d{8}\\.csv';
    44→  const stabilityThresholdMs = parseInt(process.env['STABILITY_THRESHOLD_MS'] || '2000', 10);
    45→
    46→  return {
    47→    watchPath,
    48→    quarantinePath,
    49→    pollIntervalMs,
    50→    filePattern: new RegExp(`^${filePatternStr}$`),
    51→    stabilityThresholdMs,
    52→  };
    53→}
    54→
    55→// =============================================================================
    56→// File Watcher Service
    57→// =============================================================================
    58→
    59→const log = logger.child({ module: 'file-watcher' });
    60→
    61→class FileWatcherDaemon {
    62→  private config: FileWatcherConfig;
    63→  private watcher: chokidar.FSWatcher | null = null;
    64→  private processing = new Set<string>();
    65→  private isShuttingDown = false;
    66→
    67→  constructor(config: FileWatcherConfig) {
    68→    this.config = config;
    69→  }
    70→
    71→  async start(): Promise<void> {
    72→    log.info({ config: this.config }, 'Starting file watcher daemon');
    73→
    74→    this.ensureDirectoriesExist();
    75→    await this.processExistingFiles();
    76→    this.startWatching();
    77→  }
    78→
    79→  async stop(): Promise<void> {
    80→    log.info('Stopping file watcher daemon');
    81→    this.isShuttingDown = true;
    82→
    83→    if (this.watcher) {
    84→      await this.watcher.close();
    85→      this.watcher = null;
    86→    }
    87→
    88→    log.info('File watcher daemon stopped');
    89→  }
    90→
    91→  private ensureDirectoriesExist(): void {
    92→    const dirs = [this.config.watchPath, this.config.quarantinePath];
    93→
    94→    for (const dir of dirs) {
    95→      if (!fs.existsSync(dir)) {
    96→        log.info({ path: dir }, 'Creating directory');
    97→        fs.mkdirSync(dir, { recursive: true });
    98→      }
    99→    }
   100→  }
   101→
   102→  private async processExistingFiles(): Promise<void> {
   103→    log.info({ path: this.config.watchPath }, 'Processing existing files');
   104→
   105→    try {
   106→      const files = fs.readdirSync(this.config.watchPath);
   107→      const matchingFiles = files.filter((f) => this.config.filePattern.test(f));
   108→
   109→      log.info({ count: matchingFiles.length }, 'Found existing files to process');
   110→
   111→      for (const file of matchingFiles) {
   112→        const filePath = path.join(this.config.watchPath, file);
   113→        await this.queueFile(filePath);
   114→      }
   115→    } catch (error) {
   116→      log.error({ error }, 'Failed to process existing files');
   117→    }
   118→  }
   119→
   120→  private startWatching(): void {
   121→    log.info({ path: this.config.watchPath }, 'Starting file system watcher');
   122→
   123→    this.watcher = chokidar.watch(this.config.watchPath, {
   124→      persistent: true,
   125→      ignoreInitial: true,
   126→      awaitWriteFinish: {
   127→        stabilityThreshold: this.config.stabilityThresholdMs,
   128→        pollInterval: this.config.pollIntervalMs,
   129→      },
   130→      depth: 0,
   131→      usePolling: false,
   132→    });
   133→
   134→    this.watcher.on('add', (filePath: string) => this.handleNewFile(filePath));
   135→    this.watcher.on('error', (error: unknown) => {
   136→      const err = error instanceof Error ? error : new Error(String(error));
   137→      this.handleWatchError(err);
   138→    });
   139→    this.watcher.on('ready', () => log.info('File watcher ready'));
   140→  }
   141→
   142→  private async handleNewFile(filePath: string): Promise<void> {
   143→    const fileName = path.basename(filePath);
   144→
   145→    if (this.isShuttingDown) {
   146→      log.warn({ fileName }, 'Ignoring file during shutdown');
   147→      return;
   148→    }
   149→
   150→    if (!this.config.filePattern.test(fileName)) {
   151→      log.debug({ fileName }, 'Ignoring file - does not match pattern');
   152→      return;
   153→    }
   154→
   155→    if (this.processing.has(filePath)) {
   156→      log.debug({ fileName }, 'File already being processed');
   157→      return;
   158→    }
   159→
   160→    log.info({ fileName, filePath }, 'New file detected');
   161→    await this.queueFile(filePath);
   162→  }
   163→
   164→  private async queueFile(filePath: string): Promise<void> {
   165→    const fileName = path.basename(filePath);
   166→
   167→    if (this.processing.has(filePath)) {
   168→      return;
   169→    }
   170→
   171→    this.processing.add(filePath);
   172→
   173→    try {
   174→      const stats = fs.statSync(filePath);
   175→
   176→      if (!stats.isFile()) {
   177→        log.warn({ fileName }, 'Not a regular file, skipping');
   178→        this.processing.delete(filePath);
   179→        return;
   180→      }
   181→
   182→      const jobData: IngestionJobData = {
   183→        fileName,
   184→        filePath,
   185→        fileSize: stats.size,
   186→        uploadedBy: 'file-watcher',
   187→      };
   188→
   189→      const job = await addJob(QUEUE_NAMES.INGESTION, 'process-mileage-file', jobData, {
   190→        attempts: 3,
   191→        backoff: {
   192→          type: 'exponential',
   193→          delay: 5000,
   194→        },
   195→        removeOnComplete: {
   196→          age: 24 * 60 * 60,
   197→          count: 1000,
   198→        },
   199→        removeOnFail: {
   200→          age: 7 * 24 * 60 * 60,
   201→        },
   202→      });
   203→
   204→      log.info(
   205→        {
   206→          fileName,
   207→          jobId: job.id,
   208→          fileSize: stats.size,
   209→        },
   210→        'File queued for processing'
   211→      );
   212→    } catch (error) {
   213→      log.error({ fileName, error }, 'Failed to queue file');
   214→      await this.quarantineFile(filePath, error as Error);
   215→    } finally {
   216→      this.processing.delete(filePath);
   217→    }
   218→  }
   219→
   220→  private async quarantineFile(filePath: string, error: Error): Promise<void> {
   221→    const fileName = path.basename(filePath);
   222→    const quarantinePath = path.join(
   223→      this.config.quarantinePath,
   224→      `${Date.now()}_${fileName}`
   225→    );
   226→
   227→    try {
   228→      fs.renameSync(filePath, quarantinePath);
   229→      log.warn(
   230→        {
   231→          fileName,
   232→          quarantinePath,
   233→          error: error.message,
   234→        },
   235→        'File moved to quarantine'
   236→      );
   237→    } catch (moveError) {
   238→      log.error(
   239→        {
   240→          fileName,
   241→          quarantinePath,
   242→          error: (moveError as Error).message,
   243→        },
   244→        'Failed to move file to quarantine'
   245→      );
   246→    }
   247→  }
   248→
   249→  private handleWatchError(error: Error): void {
   250→    log.error({ error: error.message }, 'File watcher error');
   251→  }
   252→}
   253→
   254→// =============================================================================
   255→// Graceful Shutdown
   256→// =============================================================================
   257→
   258→let daemon: FileWatcherDaemon | null = null;
   259→let isShuttingDown = false;
   260→
   261→async function handleShutdown(signal: string): Promise<void> {
   262→  if (isShuttingDown) {
   263→    log.warn({ signal }, 'Shutdown already in progress');
   264→    return;
   265→  }
   266→
   267→  isShuttingDown = true;
